SELECT k.id, k.category_id AS categoryId, c.name AS categoryName, k.title, k.keywords, k.status, k.updated_at AS updatedAt FROM knowledge k INNER JOIN knowledge_category c ON k.category_id = c.id WHERE k.is_deleted = 0 AND c.is_deleted = 0
AND ( k.title LIKE CONCAT('%', #{keyword}, '%') OR k.keywords LIKE CONCAT('%', #{keyword}, '%') OR k.content LIKE CONCAT('%', #{keyword}, '%') )
AND k.category_id = #{categoryId}
AND k.status = #{status}
ORDER BY k.updated_at DESC, k.id DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM knowledge k INNER JOIN knowledge_category c ON k.category_id = c.id WHERE k.is_deleted = 0 AND c.is_deleted = 0
AND ( k.title LIKE CONCAT('%', #{keyword}, '%') OR k.keywords LIKE CONCAT('%', #{keyword}, '%') OR k.content LIKE CONCAT('%', #{keyword}, '%') )
AND k.category_id = #{categoryId}
AND k.status = #{status}

SELECT k.id, k.category_id AS categoryId, c.name AS categoryName, k.title, k.keywords, k.status, k.updated_at AS updatedAt FROM knowledge k INNER JOIN knowledge_category c ON k.category_id = c.id WHERE k.is_deleted = 0 AND k.status = 1 AND c.is_deleted = 0 AND c.status = 1
AND ( k.title LIKE CONCAT('%', #{keyword}, '%') OR k.keywords LIKE CONCAT('%', #{keyword}, '%') OR k.content LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY k.updated_at DESC, k.id DESC LIMIT #{limit}
